SELECT * FROM member_info WHERE MEMBER_DELETED_DTM IS NULL
AND MEMBER_ST = #{status}
AND MEMBER_NICKNM LIKE CONCAT('%', #{keyword}, '%')
AND MEMBER_EMAIL LIKE CONCAT('%', #{keyword}, '%')
AND (MEMBER_NICKNM LIKE CONCAT('%', #{keyword}, '%') OR MEMBER_EMAIL LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY CRT_DTM DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE login_info
SET LOGOUT_DTM = CURRENT_TIMESTAMP
, LOGOUT_IP = #{logout_ip}
WHERE LOGIN_INFO_SEQ = (
    SELECT t.LOGIN_INFO_SEQ FROM (
        SELECT LOGIN_INFO_SEQ
        FROM login_info
        WHERE ADMIN_SEQ = #{admin_seq}
        AND LOGOUT_DTM IS NULL
        ORDER BY LOGIN_DTM DESC
        LIMIT 1
    ) t
)

UPDATE login_info
SET LOGOUT_DTM = CURRENT_TIMESTAMP
, LOGOUT_IP = #{logout_ip}
WHERE LOGIN_INFO_SEQ = (
    SELECT t.LOGIN_INFO_SEQ FROM (
        SELECT LOGIN_INFO_SEQ
        FROM login_info
        WHERE MEMBER_SEQ = #{member_seq}
        AND LOGOUT_DTM IS NULL
        ORDER BY LOGIN_DTM DESC
        LIMIT 1
    ) t
)

