       ADMIN_SEQ
     , NOTICE_TITLE
     , NOTICE_PRIORITY
     , ACTIVE
     , NOTICE_CONT
     , CRT_DTM
) VALUES (
       #{admin_seq}
     , #{notice_title}
     , #{notice_priority}
     , #{active}
     , #{notice_cont}
     , CURRENT_TIMESTAMP
)

